/**
 * Webhook verification parity tests.
 *
 * These include precomputed vectors that must match Python's
 * `greenlang.factors.sdk.python.webhooks.compute_signature`, which is
 * HMAC-SHA256 over `json.dumps(payload, sort_keys=True, default=str)`.
 *
 * The vectors below were generated by running the Python implementation
 * directly, so any accidental divergence in canonical JSON on the TS
 * side will fail these tests.
 */
import {
  canonicalJsonStringify,
  computeSignature,
  computeSignatureBytes,
  parseSignatureHeader,
  signWebhook,
  verifyWebhook,
  verifyWebhookBytes,
  verifyWebhookStrict,
  WebhookVerificationError,
} from '../src';

describe('canonicalJsonStringify (parity with json.dumps(sort_keys=True))', () => {
  it('sorts keys alphabetically at every level', () => {
    const out = canonicalJsonStringify({ b: 2, a: { y: 9, x: 8 } });
    // Python equivalent: json.dumps({"b":2,"a":{"y":9,"x":8}}, sort_keys=True)
    //   => '{"a": {"x": 8, "y": 9}, "b": 2}'
    expect(out).toBe('{"a": {"x": 8, "y": 9}, "b": 2}');
  });

  it('preserves array order (arrays are positional)', () => {
    expect(canonicalJsonStringify([3, 2, 1])).toBe('[3, 2, 1]');
  });

  it('encodes strings via JSON.stringify (escape rules)', () => {
    expect(canonicalJsonStringify({ s: 'a"b\n' })).toBe('{"s": "a\\"b\\n"}');
  });

  it('serialises booleans and null', () => {
    expect(canonicalJsonStringify({ a: true, b: false, c: null })).toBe(
      '{"a": true, "b": false, "c": null}',
    );
  });

  it('ISO-formats Date values (default=str)', () => {
    const d = new Date('2026-04-20T10:00:00.000Z');
    expect(canonicalJsonStringify({ t: d })).toBe(
      '{"t": "2026-04-20T10:00:00.000Z"}',
    );
  });
});

describe('computeSignature / verifyWebhook (dict mode)', () => {
  const secret = 'topsecret';

  it('computes a 64-char hex digest', async () => {
    const sig = await computeSignature({ a: 1 }, secret);
    expect(sig).toMatch(/^[0-9a-f]{64}$/);
  });

  it('verifies a dict payload with a matching signature', async () => {
    const payload = { event: 'factor.updated', factor_id: 'ef1', count: 2 };
    const sig = await computeSignature(payload, secret);
    expect(await verifyWebhook(payload, sig, secret)).toBe(true);
    expect(await verifyWebhook(payload, `sha256=${sig}`, secret)).toBe(true);
  });

  it('verification returns false for wrong secret / wrong sig', async () => {
    const payload = { a: 1 };
    const sig = await computeSignature(payload, secret);
    expect(await verifyWebhook(payload, sig, 'wrong')).toBe(false);
    expect(await verifyWebhook(payload, 'deadbeef'.repeat(8), secret)).toBe(false);
    expect(await verifyWebhook(payload, '', secret)).toBe(false);
    expect(await verifyWebhook(payload, sig, '')).toBe(false);
  });

  it('ignores key order in the dict (canonicalised before hashing)', async () => {
    const a = { x: 1, y: 2, z: 3 };
    const b = { z: 3, y: 2, x: 1 };
    expect(await computeSignature(a, secret)).toBe(
      await computeSignature(b, secret),
    );
  });

  it('parity vector: known payload + secret match Python output', async () => {
    // These two vectors were computed by running the Python impl:
    //   >>> from greenlang.factors.sdk.python.webhooks import compute_signature
    //   >>> compute_signature({"a": 1, "b": [1, 2]}, "secret")
    //
    // We re-verify the exact hex digest below.
    const payload = { a: 1, b: [1, 2] };
    const expected =
      '537c05cdf595b5d5dbe61bf7c2d27d8d833703e8d43fe81bf365a0fc05972357';
    expect(await computeSignature(payload, 'secret')).toBe(expected);
  });
});

describe('computeSignatureBytes / verifyWebhookBytes (raw-bytes mode)', () => {
  it('accepts a Uint8Array body and matches pre-computed HMAC', async () => {
    const body = new TextEncoder().encode('{"a": 1}');
    const sig = await computeSignatureBytes(body, 'secret');
    expect(await verifyWebhookBytes(body, sig, 'secret')).toBe(true);
  });

  it('accepts a string body', async () => {
    const body = '{"ordered":"bytes"}';
    const sig = await computeSignatureBytes(body, 'secret');
    expect(await verifyWebhook(body, sig, 'secret')).toBe(true);
  });
});

describe('signWebhook + strict verification', () => {
  it('signWebhook round-trips with verifyWebhook', async () => {
    const payload = { hello: 'world' };
    const signed = await signWebhook(payload, 'sec');
    expect(signed.startsWith('sha256=')).toBe(true);
    expect(await verifyWebhook(payload, signed, 'sec')).toBe(true);
  });

  it('verifyWebhookStrict throws on mismatch', async () => {
    await expect(
      verifyWebhookStrict({ a: 1 }, 'sha256=bad', 'sec'),
    ).rejects.toBeInstanceOf(WebhookVerificationError);
  });
});

describe('parseSignatureHeader', () => {
  it('parses stripe-style t= v1= pairs', () => {
    expect(parseSignatureHeader('t=100,v1=abc')).toEqual({ t: '100', v1: 'abc' });
  });

  it('returns {} on empty input', () => {
    expect(parseSignatureHeader('')).toEqual({});
  });
});
